B.KW=s(["Gire pesco\xe7o, ombros, quadril, joelhos e tornozelos sem pressa.","Movimentos amplos e suaves, sem for\xe7ar.","Objetivo: soltar as articula\xe7\xf5es e elevar a temperatura do corpo."],t.s)
B.HZ=new A.bq("aquecimento-articular",B.KW,"Aquecimento articular",B.c8)
B.Oq=s(["Deitado de bru\xe7os, bra\xe7os estendidos \xe0 frente.","Eleve bra\xe7os, peito e pernas ao mesmo tempo, contraindo as costas.","Segure 2 segundos no topo e des\xe7a devagar.","Sem for\xe7ar o pesco\xe7o \u2014 olhar para o ch\xe3o."],t.s)
B.I0=new A.bq("superman",B.Oq,"Superman",B.iM)
B.Mn=s(["Deite sob uma mesa firme e segure a borda com as duas m\xe3os.","Corpo reto, calcanhares no ch\xe3o.","Puxe o peito em dire\xe7\xe3o \xe0 mesa, juntando as esc\xe1pulas.","Des\xe7a controlando. Quanto mais horizontal o corpo, mais dif\xedcil."],t.s)
B.It=new A.bq("remada-mesa",B.Mn,"Remada na mesa (australiana)",B.iM)
B.LX=s(["De bru\xe7os, eleve bra\xe7o direito e perna esquerda juntos.","Alterne com o lado oposto, como se nadasse.","Movimento cont\xednuo e controlado, abd\xf4men firme."],t.s)
B.HY=new A.bq("nadador",B.LX,"Nadador",B.iM)
B.LW=s(["Sente na beirada de uma cadeira firme, m\xe3os ao lado do quadril.","Deslize o corpo \xe0 frente e des\xe7a dobrando os cotovelos para tr\xe1s.","Cotovelos apontando para tr\xe1s (n\xe3o para os lados).","Suba empurrando com os tr\xedceps. Pernas mais estendidas = mais dif\xedcil."],t.s)
B.Iq=new A.bq("mergulho-cadeira",B.LW,"Mergulho na cadeira (tr\xedceps)",B.iN)
B.N3=s(["Segure uma toalha com uma m\xe3o por baixo e pise/segure a outra ponta.","Puxe como uma rosca de b\xedceps, resistindo com a outra ponta.","Segure a contra\xe7\xe3o por 10\u201320 segundos e troque o bra\xe7o."],t.s)
B.I6=new A.bq("rosca-isometrica",B.N3,"Rosca isom\xe9trica com toalha",B.iN)
B.On=s(["Apoie as m\xe3os numa superf\xedcie elevada (mesa, sof\xe1, parede).","Corpo reto da cabe\xe7a aos calcanhares, abd\xf4men firme.","Des\xe7a o peito em dire\xe7\xe3o ao apoio e empurre de volta.","Quanto mais alto o apoio, mais f\xe1cil \u2014 comece confort\xe1vel."],t.s)
B.Id=new A.bq("flexao-inclinada",B.On,"Flex\xe3o inclinada",B.co)
B.Mb=s(["Joelhos no ch\xe3o, tronco e quadril alinhados (sem empinar).","M\xe3os na largura dos ombros.","Des\xe7a o peito at\xe9 perto do ch\xe3o e suba controlando."],t.s)
B.I3=new A.bq("flexao-joelhos",B.Mb,"Flex\xe3o de joelhos",B.co)
