B.Ib=new A.bq("flexao-diamante",B.MA,"Flex\xe3o diamante (tr\xedceps)",B.iN)
B.Mz=s(["P\xe9s apoiados numa eleva\xe7\xe3o (banco, degrau).","Corpo reto, abd\xf4men firme, olhar para o ch\xe3o.","Des\xe7a o peito e empurre \u2014 foco na parte alta do peitoral."],t.s)
B.Ih=new A.bq("flexao-declinada",B.Mz,"Flex\xe3o declinada",B.co)
B.O4=s(["M\xe3os bem afastadas; des\xe7a deslocando o peso para um lado.",'Um bra\xe7o dobra, o outro estica ("como um arqueiro").',"Alterne os lados a cada repeti\xe7\xe3o."],t.s)
B.Ik=new A.bq("flexao-arqueiro",B.O4,"Flex\xe3o arqueiro",B.co)
B.Nj=s(["Des\xe7a controlado e suba com for\xe7a, tirando as m\xe3os do ch\xe3o.","Amorte\xe7a a queda dobrando os cotovelos.","S\xf3 avance para ela com a flex\xe3o tradicional bem s\xf3lida."],t.s)
B.Ir=new A.bq("flexao-explosiva",B.Nj,"Flex\xe3o explosiva",B.co)
