B.I9=new A.bq("flexao-palma",B.Mm,"Flex\xe3o com palma",B.co)
B.MZ=s(["Prancha alta: corpo reto da cabe\xe7a aos calcanhares.","M\xe3os na largura dos ombros, cotovelos a ~45\xb0 do tronco.","Des\xe7a o peito at\xe9 quase tocar o ch\xe3o e suba controlando.","Mantenha o abd\xf4men e os gl\xfateos contra\xeddos o tempo todo."],t.s)
B.Ix=new A.bq("flexao-tradicional",B.MZ,"Flex\xe3o tradicional",B.co)
