B.If=new A.bq("agachamento-livre",B.Ml,"Agachamento livre",B.cS)
B.Ma=s(["D\xea um passo \xe0 frente e des\xe7a o joelho de tr\xe1s em dire\xe7\xe3o ao ch\xe3o.","Joelho da frente alinhado com o tornozelo (n\xe3o passa do p\xe9).","Alterne as pernas mantendo o tronco ereto."],t.s)
B.I5=new A.bq("afundo",B.Ma,"Afundo (passada)",B.cS)
