B.NK=s(["Apoio no antebra\xe7o e na lateral do p\xe9, corpo reto.","Quadril elevado, sem deixar cair.","Segure o tempo indicado e troque de lado."],t.s)
B.Im=new A.bq("prancha-lateral",B.NK,"Prancha lateral",B.cT)
B.NI=s(["Na prancha alta, toque o ombro oposto com a m\xe3o.","Evite balan\xe7ar o quadril \u2014 mantenha est\xe1vel.","Alterne as m\xe3os com controle."],t.s)
B.Ic=new A.bq("prancha-toque-ombro",B.NI,"Prancha com toque no ombro",B.cT)
